function toBool(value, fallback = false) {
  if (typeof value === 'boolean') return value;
  if (value === undefined || value === null || value === '') return fallback;
  const normalized = String(value).trim().toLowerCase();
  return ['true', '1', 'yes', 'y'].includes(normalized);
}

function toInt(value, fallback) {
  const n = Number(value);
  if (!Number.isFinite(n) || n < 0) return fallback;
  return Math.floor(n);
}

function normalizeKeywords(value) {
  if (Array.isArray(value)) return value.map((v) => String(v).trim()).filter(Boolean);
  return String(value || '')
    .split(',')
    .map((v) => v.trim())
    .filter(Boolean);
}

const items = $input.all();

const payload = items[0].json || {};

const apifyToken = String(payload.apifyToken || '').trim();
const keywords = normalizeKeywords(payload.keywords || payload.searchQueries || payload.search_queries);
const spreadsheetId = String(payload.spreadsheetId || '').trim();
const sheetName = String(payload.sheetName || 'Sheet1').trim();

const maxPosts = toInt(payload.maxPosts, 30);
const sortBy = ['relevance', 'date'].includes(String(payload.sortBy || '').toLowerCase())
  ? String(payload.sortBy).toLowerCase()
  : 'date';
const postedLimit = String(payload.postedLimit || 'month').trim();
const scrapeComments = toBool(payload.scrapeComments, false);
const scrapeReactions = toBool(payload.scrapeReactions, false);
const maxComments = toInt(payload.maxComments, 0);
const maxReactions = toInt(payload.maxReactions, 0);

const missing = [];
if (!apifyToken) missing.push('apifyToken');
if (!keywords.length) missing.push('keywords');
if (!spreadsheetId) missing.push('spreadsheetId');
if (!sheetName) missing.push('sheetName');

const apifyInput = {
  searchQueries: keywords,
  maxPosts,
  sortBy,
  postedLimit,
  scrapeComments,
  scrapeReactions,
  maxComments,
  maxReactions
};

return [{
  json: {
    isValid: missing.length === 0,
    missingFields: missing,
    apifyToken,
    spreadsheetId,
    sheetName,
    keywordsCsv: keywords.join(', '),
    apifyInput
  }
}];

function pick(obj, paths, fallback = '') {
  for (const path of paths) {
    const chunks = path.split('.');
    let cur = obj;
    for (const c of chunks) cur = cur?.[c];
    if (cur !== undefined && cur !== null && String(cur).trim() !== '') return cur;
  }
  return fallback;
}

const cfg = $('Normalize Inputs').first().json;
const raw = [];

for (const item of items) {
  const j = item.json;
  if (Array.isArray(j)) {
    raw.push(...j);
    continue;
  }
  if (Array.isArray(j?.data)) {
    raw.push(...j.data);
    continue;
  }
  if (Array.isArray(j?.items)) {
    raw.push(...j.items);
    continue;
  }
  if (Array.isArray(j?.body)) {
    raw.push(...j.body);
    continue;
  }
  if (j && typeof j === 'object' && (j.linkedinUrl || j.postUrl || j.url || j.content)) {
    raw.push(j);
  }
}

const rows = raw
  .filter((p) => p && typeof p === 'object')
  .map((post) => ({
    hasRows: true,
    linkedinposturl: String(pick(post, ['linkedinUrl', 'postUrl', 'url'], '')),
    content: String(pick(post, ['content', 'text', 'postText'], ''))
  }))
  .filter((r) => r.linkedinposturl || r.content);

if (!rows.length) {
  return [{
    json: {
      hasRows: false,
      rowCount: 0,
      keyword_input: cfg.keywordsCsv,
      message: 'No posts were returned by Apify actor for the provided keywords.'
    }
  }];
}

return rows.map((r) => ({ json: r }));

const cfg = $('Normalize Inputs').first().json;
return [{
  json: {
    success: true,
    message: `Stored ${items.length} LinkedIn posts into Google Sheets.`,
    rows_written: items.length,
    spreadsheet_id: cfg.spreadsheetId,
    sheet_name: cfg.sheetName,
    keywords: cfg.keywordsCsv,
    actor_id: 'harvestapi~linkedin-post-search',
    generated_at: new Date().toISOString()
  }
}];

return [{
  json: {
    success: false,
    message: item.json.message || 'No data to write into Google Sheets.',
    rows_written: 0,
    keywords: item.json.keyword_input || '',
    actor_id: 'harvestapi~linkedin-post-search',
    generated_at: new Date().toISOString()
  }
}];

return [{
  json: {
    success: false,
    message: 'Missing required input fields. Update Set Inputs (Edit Before Active).',
    required_fields: ['apifyToken', 'keywords', 'spreadsheetId', 'sheetName'],
    missing_fields: item.json.missingFields || [],
    generated_at: new Date().toISOString()
  }
}];

const seen = new Set();
const column = "linkedinposturl"; // change this to your column name

return items.filter(item => {
  const value = item.json[column];

  if (!value) return false; // drop empty values (optional)

  if (seen.has(value)) {
    return false;
  } else {
    seen.add(value);
    return true;
  }
});

