let raw;

// Case 1: OpenAI-style response
if ($json.choices?.[0]?.message?.content) {
  raw = $json.choices[0].message.content;
}

// Case 2: New response format (output → content → text)
else if ($json.output?.[0]?.content?.[0]?.text) {
  raw = $json.output[0].content[0].text;
}

else {
  throw new Error("Unsupported AI response format");
}

if (!raw) {
  throw new Error("Empty AI response");
}

// Step 1: clean markdown
let cleaned = raw
  .replace(/```json/g, '')
  .replace(/```/g, '')
  .trim();

// Step 2: aggressively trim garbage around JSON
cleaned = cleaned
  .replace(/^[^[{]*/, '')   // remove anything before JSON starts
  .replace(/[^}\]]*$/, ''); // remove anything after JSON ends

// Step 3: extract object OR array
const match = cleaned.match(/(\{[\s\S]*\}|\[[\s\S]*\])/);

if (!match) {
  throw new Error("No JSON found in AI response");
}

let parsed;

try {
  parsed = JSON.parse(match[0]);
} catch (e) {
  throw new Error("JSON parsing failed: " + e.message);
}

// Normalize output (VERY IMPORTANT for n8n)
if (Array.isArray(parsed)) {
  return parsed.map(item => ({ json: item }));
} else {
  return [{ json: parsed }];
}

